package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.doWork;
import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;

/**
 * A scorer that maximizes ideal parallelism using anti-diagonal wavefront pattern.
 */
public class IdealParScoring extends AbstractDnaScoring {

    /**
     * The length of the first sequence.
     */
    private final int xLength;

    /**
     * The length of the second sequence.
     */
    private final int yLength;

    /**
     * The Smith-Waterman matrix.
     */
    private final int[][] matrix;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
        scoringRunner.start("IdealParScoring", args);
    }

    /**
     * Creates a new IdealParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public IdealParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        this.xLength = xLength;
        this.yLength = yLength;
        matrix = new int[xLength + 1][yLength + 1];

        // Initialize boundaries
        matrix[0][0] = 0;
        for (int i = 1; i <= xLength; i++) {
            matrix[i][0] = getScore(1, 0) * i;
        }
        for (int j = 1; j <= yLength; j++) {
            matrix[0][j] = getScore(0, 1) * j;
        }
    }

    /**
     * Parallel Smith-Waterman using anti-diagonal wavefront to maximize ideal parallelism.
     * Each anti-diagonal is processed in parallel; cells on the same diagonal are independent.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        // Process anti-diagonals d = i + j, from 2 to xLength + yLength
        for (int d = 2; d <= xLength + yLength; d++) {
            final int diag = d;
            finish(() -> {
                final int iStart = Math.max(1, diag - yLength);
                final int iEnd = Math.min(diag - 1, xLength);
                for (int i = iStart; i <= iEnd; i++) {
                    final int ii = i;
                    final int jj = diag - ii;
                    async(() -> {
                        doWork(1);
                        final char xChar = x.charAt(ii - 1);
                        final char yChar = y.charAt(jj - 1);
                        final int diagScore = matrix[ii - 1][jj - 1]
                            + getScore(charMap(xChar), charMap(yChar));
                        final int topScore = matrix[ii - 1][jj]
                            + getScore(charMap(xChar), 0);
                        final int leftScore = matrix[ii][jj - 1]
                            + getScore(0, charMap(yChar));
                        matrix[ii][jj] = Math.max(diagScore,
                            Math.max(leftScore, topScore));
                    });
                }
            });
        }
        return matrix[xLength][yLength];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.forallPhased;
import static edu.rice.hj.Module0.next;
import static edu.rice.hj.Module0.numWorkerThreads;

/**
 * A scorer that allocates memory during computation, so that it may compute the scores for two sequences without
 * requiring O(|X||Y|) memory. Uses anti-diagonal sparse storage with only 3 diagonal buffers.
 */
public class SparseParScoring extends AbstractDnaScoring {

    /**
     * The length of the first sequence.
     */
    private final int xLength;

    /**
     * The length of the second sequence.
     */
    private final int yLength;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Creates a new SparseParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        this.xLength = xLength;
        this.yLength = yLength;
    }

    /**
     * Parallel sparse Smith-Waterman using anti-diagonal wavefront with 3 diagonal buffers.
     * Memory usage is O(min(xLength, yLength)) instead of O(xLength * yLength).
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int numTasks = numWorkerThreads();
        final int maxDiagLen = Math.min(xLength, yLength);
        final int[][] diagBuf = new int[3][maxDiagLen];

        // Gap penalties (constant for any character)
        final int gapY = getScore(1, 0); // M[char][gap] = -4, used for S[i][0] = gapY * i
        final int gapX = getScore(0, 1); // M[gap][char] = -2, used for S[0][j] = gapX * j

        forallPhased(0, numTasks - 1, (k) -> {
            for (int d = 2; d <= xLength + yLength; d++) {
                final int iSt = Math.max(1, d - yLength);
                final int iEn = Math.min(d - 1, xLength);
                final int dLen = iEn - iSt + 1;

                final int perTask = (dLen + numTasks - 1) / numTasks;
                final int localStart = iSt + k * perTask;
                final int localEnd = Math.min(localStart + perTask - 1, iEn);

                // Buffer indices for current, previous, and two-back diagonals
                final int bc = d % 3;
                final int bp = (d + 2) % 3;  // (d-1) % 3
                final int bp2 = (d + 1) % 3; // (d-2) % 3

                // Starting i-index for previous and two-back diagonals
                final int iStPrev = Math.max(1, d - 1 - yLength);
                final int iStPrev2 = Math.max(1, d - 2 - yLength);

                for (int i = localStart; i <= localEnd; i++) {
                    final int j = d - i;
                    final char xChar = x.charAt(i - 1);
                    final char yChar = y.charAt(j - 1);
                    final int xIdx = charMap(xChar);
                    final int yIdx = charMap(yChar);

                    // S[i-1][j-1] on diagonal d-2
                    int prevDiag;
                    if (i == 1 && j == 1) {
                        prevDiag = 0;
                    } else if (i == 1) {
                        prevDiag = gapX * (j - 1);
                    } else if (j == 1) {
                        prevDiag = gapY * (i - 1);
                    } else {
                        prevDiag = diagBuf[bp2][(i - 1) - iStPrev2];
                    }

                    // S[i-1][j] on diagonal d-1
                    int prevTop;
                    if (i == 1) {
                        prevTop = gapX * j;
                    } else {
                        prevTop = diagBuf[bp][(i - 1) - iStPrev];
                    }

                    // S[i][j-1] on diagonal d-1
                    int prevLeft;
                    if (j == 1) {
                        prevLeft = gapY * i;
                    } else {
                        prevLeft = diagBuf[bp][i - iStPrev];
                    }

                    final int diagScore = prevDiag + getScore(xIdx, yIdx);
                    final int topScore = prevTop + getScore(xIdx, 0);
                    final int leftScore = prevLeft + getScore(0, yIdx);

                    diagBuf[bc][i - iSt] = Math.max(diagScore,
                        Math.max(topScore, leftScore));
                }
                next();
            }
        });

        // Last diagonal d = xLength + yLength has one cell at (xLength, yLength)
        return diagBuf[(xLength + yLength) % 3][0];
    }

}

