                final int diagLen = iEnd - iStart + 1;

                final int perTask = (diagLen + numTasks - 1) / numTasks;
                final int localStart = iStart + k * perTask;
                final int localEnd = Math.min(localStart + perTask - 1, iEnd);

                for (int i = localStart; i <= localEnd; i++) {
                    final int j = d - i;
                    final char xChar = x.charAt(i - 1);
